+        // Grow if needed
+        if (self.count >= self.capacity) {
+            try self.grow();
+        }
+
+        const row = self.count;
+        self.count += 1;
+
+        // Store values in columnar layout
+        for (0..self.field_count) |i| {
+            self.columns[i][row] = values[i];
+        }
+
+        try self.addr_to_row.put(self.allocator, js_addr, row);
